/* C-runtime linker script for hybrid round-trip fixtures.
 *
 * Loads at 0x80000000 (QEMU virt RAM base, also inside vsim's RAM region
 * RAM_BASE..RAM_END = 0x0..0x8FFFFFFF). Preserves .data/.bss/.rodata so C
 * programs with global state can link, and exposes _edata/_end (consumed by
 * crt0.S's bss-clear loop) and _stack (consumed by crt0.S's sp init).
 */

ENTRY(_start)

SECTIONS {
    . = 0x80000000;

    .text : {
        *(.text.init)
        *(.text*)
    }

    .rodata : {
        *(.rodata*)
        *(.srodata*)
    }

    .data : {
        *(.data*)
        *(.sdata*)
    }
    _edata = .;

    .bss : {
        *(.bss*)
        *(.sbss*)
        *(COMMON)
    }
    _end = .;

    /* _stack sits in QEMU virt's default 128 MiB RAM (0x80000000..0x88000000)
     * and inside vsim RAM. Override at link time with -Wl,--defsym,_stack=...
     * if you change QEMU -m or vsim memory layout. */
    PROVIDE(_stack = 0x80700000);
}

/* Drain markers and fail-fast helper shared by all C-level round-trip
 * fixtures (rt_c_hello.c, rt_c_printf.c, rt_c_file_io.c).
 *
 * The fixtures are timing-aware: only the span between rt_phase_qemu1_drain()
 * and rt_phase_vsim_drain() may touch libgloss / sim_control MMIO. Outside
 * that window the program runs on QEMU virt, which has no peripheral at
 * 0xE0080000.
 */

#ifndef RT_C_HELPERS_H
#define RT_C_HELPERS_H

#include <stdint.h>
#include <stdio.h>

/* Matches src/platform/sim_control.hpp:32 SimCommand::FAILED. */
#define SIM_CONTROL_REG (*(volatile uint32_t*) 0xE0080000)
#define SIM_FAILED 0x01234569u

/* Plugin- / handoff-controller-recognized drain markers (CSR 0x7C0,
 * uimm 0 = ENTER, uimm 1 = EXIT). Match insn_match.h. */
static inline void rt_phase_qemu1_drain(void)
{
  __asm__ __volatile__("csrwi 0x7C0, 0");
}
static inline void rt_phase_vsim_drain(void)
{
  __asm__ __volatile__("csrwi 0x7C0, 1");
}

/* Vsim-only failure path: writes SimCommand::FAILED so vsim's
 * handle_sim_command (sim_control.hpp:188) sets exits=1 and the simulator
 * loop returns 1 before the handoff fires. The harness sees RC=1 vs
 * EXPECT_RC=0 and reports a failure. Bypasses QEMU2 entirely. */
__attribute__((noreturn)) static inline void rt_fail(void)
{
  fflush(stdout);
  SIM_CONTROL_REG = SIM_FAILED;
  for (;;) {
  }
}

/* RISC-V semihosting calls. Only safe in the QEMU2 phase (after
 * rt_phase_vsim_drain): QEMU is spawned with -semihosting-config
 * enable=on,target=native (qemu_handback.hpp:131-132) so the magic
 * slli/ebreak/srai triple is intercepted before reaching mtvec. vsim
 * does NOT implement semihosting, so executing these inside the vsim
 * span would route to m_trap_entry -> exception_handler and loop. */
static inline void rt_semihost_writes(const char* s)
{
  register long a0 __asm__("a0") = 0x04; /* SYS_WRITE0 */
  register long a1 __asm__("a1") = (long) (uintptr_t) s;
  __asm__ __volatile__(".option push\n"
                       ".option norvc\n"
                       "slli x0, x0, 0x1f\n"
                       "ebreak\n"
                       "srai x0, x0, 0x7\n"
                       ".option pop\n"
                       :
                       : "r"(a0), "r"(a1)
                       : "memory");
}

#endif /* RT_C_HELPERS_H */

// rt_pc_jump.S
//
// Tier-1 fixture: verifies DPC fidelity at the vsim->QEMU2 boundary.
//
// Phase A (QEMU1): csrwi 0x7C0, 0  -> drain & exit.
// Phase B (vsim):  jump 64 bytes forward, then csrwi 0x7C0, 1 -> drain.
//                  state_drain captures DPC = PC of insn after csrwi.
//                  If DPC is stale (e.g., points to the linear PC after the
//                  jump source instead of after the post-jump csrwi), QEMU2
//                  resumes at the wrong location and never exits cleanly.
// Phase C (QEMU2): semihosting exit with code 0.

#include "semihost_exit.inc"

.section .text
.globl _start
_start:
    csrwi   0x7C0, 0                 // QEMU1 drains, exits

    // Phase B: jump forward 0x40 bytes; everything in between is dead code
    // that would set the wrong DPC if the jump were not taken.
    j       phase_b_landing
    .rept   15
    csrwi   0x7C0, 1                 // poison: would re-trigger drain
    .endr

phase_b_landing:
    csrwi   0x7C0, 1                 // vsim drains here; DPC must point at phase_c

phase_c:
    li      a2, 0
    SEMIHOST_EXIT a2

