private:
  // debug
  jtag_dtm& dtm;
  bool dtm_debug = false;
  TraceController<CPU> trace_;

  // Hybrid handoff (vsim->QEMU). Order matters: dmi_bus_ is referenced by
  // handoff_, so it must be declared first.
  std::unique_ptr<hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width,
                                        PLATFORM::dmi_data_width>>
    hybrid_dmi_bus_;
  std::optional<hybrid::HandoffController> hybrid_handoff_;
  std::string hybrid_state_path_;
  std::optional<hybrid_state_v1> hybrid_input_state_;

  using xlen_t = std::conditional_t<CPU::NDS_XLEN <= 32, uint32_t, uint64_t>;

public:
  ContextManager<CPU> context_config;

  Simulator(const sc_core::sc_module_name& name,
            std::span<uint8_t> ram_buffer = {},
            MemoryRegion ram_region = {RAM_BASE, RAM_END},
            MemoryRegion ram_alias_region = {RAM_ALIAS_BASE, RAM_ALIAS_END})
      : sc_core::sc_module{name},
        platform("platform", ram_buffer, ram_region, ram_alias_region),
        dtm(platform.dtm)
  {
    cpu.bind(platform.clk, platform.resetn, platform.reset_vector,
             platform.dmi_signals, platform.wfi_signal, platform.int_trigger);

// End-to-end roundtrip fixture:
//   1. QEMU + plugin sees `csrwi 0x7C0, 0` -> drains state, exits.
//   2. vsim resumes, computes a2=3.
//   3. vsim sees `csrwi 0x7C0, 1` -> drains state, exits 200.
//   4. main spawns qemu-system -gdb -S -semihosting; resume restores GPRs.
//   5. QEMU runs to the semihosting EXIT_EXTENDED triple and exits with a1=3.

#include "semihost_exit.inc"

.section .text
.globl _start
_start:
    csrwi   0x7C0, 0          // entry: QEMU drains, exits
    li      a0, 1
    li      a1, 2
    add     a2, a0, a1        // a2 = 3, computed in vsim only
    csrwi   0x7C0, 1          // exit: vsim drains, exit 200
    SEMIHOST_EXIT a2

// rt_csr_survival.S
//
// Tier-1 fixture: M-mode CSRs survive QEMU1 -> vsim -> QEMU2.
// Verifies the CSR pass-through merge in HandoffController and the
// feature-aware P-packet path in qemu_handback.
//
// Phase A (QEMU1): write distinguishable values to mscratch, mtvec, and
//                  mepc, then trigger the entry handoff.
// Phase B (vsim):  no-op.  vsim does not modify these CSRs; they must
//                  pass through the input-state snapshot kept by
//                  HandoffController and arrive at QEMU 2 unchanged.
// Phase C (QEMU2): csrr each CSR back into a GPR, compare. Exit code is
//                  the CSR index of the first mismatch (1=mscratch,
//                  2=mtvec, 3=mepc), 0 on full pass.
//
// mtvec is written with a 4-byte aligned value (mode=Direct) so QEMU
// accepts it without rounding the low bits.

#include "semihost_exit.inc"

.section .text
.globl _start
