  hybrid::CsrTrigger trigger;
  trigger.add_pc_hit(0x80000044, HYBRID_HANDOFF_EXIT);

  hybrid::HandoffController h(std::move(trigger), bus);
  const auto state = h.on_retire(0x80000044, [](uint8_t) { return 0u; });

  REQUIRE(state);
  CHECK(state->magic == HYBRID_STATE_MAGIC);
  CHECK(state->gpr[12] == 7);
  CHECK(state->pc == 0x80000048);
}

