// Linker symbols provided config.o, see print_cpu_configuration()
extern char _binary_config_inc_start;
extern char _binary_config_inc_end;

extern "C" const char* get_libaceasim_version() __attribute__((weak));

static void print_cpu_configuration()
{
  // these symbols are defined in obj_sc/config.o
  // they come from andes_ip/kv_core/top/hdl/config.inc
  char* start = &_binary_config_inc_start;
  char* end = &_binary_config_inc_end;
  fwrite(start, 1, end - start, stdout);
}

static void print_version()
{
  fmt::print(
    "Copyright (C) 2013-2026 Andes Technology Corporation. All rights reserved.\n");
  fmt::print("Version : {}\n\n", ANDESCYCLE_VERSION);

  // output ACE, ACERVV support version
  if (get_libaceasim_version)
    fmt::print("Andes Custom Extension : {}\n", get_libaceasim_version());
}

static void print_help()
{
  print_version();
  fmt::print(R"(
Usage: sim_cpu_name [elf_file] [options]

AndesCycle CPU simulator for RISC-V processors

Argument:
  <elf_file>                  RISC-V ELF binary to simulate

General:
  --help, -h                  Print this help message and exit
  --version                   Display version information and exit
  --print-config              Show CPU configuration and exit
  --print-memmap              Show memory map layout and exit
  --log-level <level>         Set logging verbosity [default: 2]
                              (0=trace 1=debug 2=info 3=warn 4=error 5=critical 6=off)

Simulation:
  --mem-latency  <cycles>     Memory access latency in cycles [default: 1]
  --reset-vector <spec>       Set per-hart reset vector
                              <addr>        set all harts to <addr>
                              <hart>:<addr> set specific hart to <addr>
                              Overrides ELF entrypoint if specified

Tracing:
  --pc-trace  <file>          Enable PC trace logging to CSV file
  --kanata    <file>          Enable Kanata pipeline visualization logging
  --clarity   <file>          Enable Clarity pipeline visualization logging
  --objdump   <file>          Load objdump disassembly for pipeline viewer labels
  --kanata-loop-start <pc>    Start PC of the loop body (hex with 0x ok)
  --kanata-loop-end   <pc>    End PC of the loop body. Each retire of this PC
                              counts as one iteration; combine with --kanata or
                              --clarity to dump a steady-state window
  --kanata-loop-skip  <N>     Skip first N iterations [default: 0]
  --kanata-loop-record <X>    Record next X iterations then exit [default: 1]

Debug:
  --jtag-port <port>          JTAG remote bitbang port for OpenOCD [default: 9104]

Extra Options (require additional license):
  --ilm       <image>         Load ILM ROM image
  --dlm       <image>         Load DLM ROM image
  --waveform  <file>          Enable VCD/FST waveform tracing
  --save                      Save context when CPU enters WFI
  --continue                  Restore context and resume execution
  --context-dir <dir>         Context directory [default: ./saved_ctx]

Hybrid (QEMU + Verilator):
  --shared-mem-path <file>    mmap-backed file used as main RAM (zero-copy
                              shared with QEMU). Requires --shared-mem-size.
  --shared-mem-size <bytes>   Size of the shared mmap region; must cover the
                              full main memory range
  --shared-mem-base <hex>     Guest physical address that file offset 0 maps
                              to. Default 0x80000000 (QEMU virt RAM base);
                              override only for non-virt machine types.
  --resume-from-qemu <file>   Resume from a QEMU-side state snapshot.
                              Mutually exclusive with --continue.
  --handoff-out <file>        Drain architectural state to <file> when
                              `csrwi 0x7C0, 1` retires; exit with code 200.
  --qemu-binary <path>        On handoff drain, spawn this qemu-system-riscv64
                              with -gdb -S -semihosting, restore state via
                              gdbstub, and propagate QEMU's exit code.
)");
  // --ilm/--dlm: CPU-specific, not all CPUs have ILM/DLM
  // --waveform: requires compile flag VSIMDEBUG
  // --save/--continue/--context-dir: requires compile flag VSIMSAVABLE
}

